<?php namespace App\Repositories\Student;use App\Repositories\BaseRepository;use App\Models\Student\StudentDocument;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class StudentDocumentRepository extends BaseRepository{    public function __construct(StudentDocument $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByStudent(int $studentId): Collection    {        return $this->findByField('student_id', $studentId);    }    public function findByDocumentType(string $documentType): Collection    {        return $this->findByField('document_type', $documentType);    }    public function findByStudentAndType(int $studentId, string $documentType): Collection    {        return $this->query()->where('student_id', $studentId)->where('document_type', $documentType)->get();    }    public function getVerifiedDocuments(): Collection    {        return $this->query()->where('is_verified', true)->get();    }    public function getPendingVerification(): Collection    {        return $this->query()->where('is_verified', false)->get();    }    public function markAsVerified(int $id): bool    {        return $this->update($id, ['is_verified' => true, 'verified_at' => now()]);    }    public function countByType(): Collection    {        return $this->query()->selectRaw('document_type, COUNT(*) as total')->groupBy('document_type')->get();    }}